import React, { useState, useEffect } from "react";
import { Search, Loader } from "lucide-react";
import { fetchPaidSearchResults } from "../api";  // Implement this API call in your api.js


const PAID_API_PROVIDERS = [
  { id: "tavily", name: "Tavily" },
  // Add more providers here as you integrate them
];

export default function PaidSearchTab({ token, onSaveArticle }) {
  const [query, setQuery] = useState("");
  const [selectedProviders, setSelectedProviders] = useState([]);
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const pageSize = 10;

  const fetchResults = async () => {
    if (!query || selectedProviders.length === 0) {
      setResults([]);
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const response = await fetch("/api/paid_search/", {
        method: "POST",
        headers: { 
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`
        },
        body: JSON.stringify({
          query,
          providers: selectedProviders,
          limit: pageSize,
          offset: (page - 1) * pageSize,
        }),
      });
      if (!response.ok) throw new Error("API Error");
      const data = await response.json();
      setResults(data);
    } catch (e) {
      setError("Failed to fetch paid API results.");
      setResults([]);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchResults();
  }, [query, selectedProviders, page]);

  const toggleProvider = (id) => {
    setSelectedProviders((prev) =>
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    );
  };

  return (
    <div className="p-4">
      <h2 className="text-xl font-semibold mb-4">Paid API Search</h2>
      <input
        type="text"
        placeholder="Enter search query..."
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        className="border p-2 rounded w-full mb-3"
      />
      <div className="mb-3">
        <span className="font-semibold mr-2">Select Providers:</span>
        {PAID_API_PROVIDERS.map(p => (
          <label key={p.id} className="mr-4 cursor-pointer">
            <input
              type="checkbox"
              checked={selectedProviders.includes(p.id)}
              onChange={() => toggleProvider(p.id)}
              className="mr-1"
            />
            {p.name}
          </label>
        ))}
      </div>
      {loading && <div>Loading results...</div>}
      {error && <div className="text-red-600">{error}</div>}
      {!loading && results.length === 0 && <div>No results found.</div>}
      <div>
        {results.map((article, idx) => (
          <div key={idx} className="border p-3 mb-2 rounded">
            <a href={article.link} target="_blank" rel="noopener noreferrer" className="font-semibold text-blue-700">
              {article.title}
            </a>
            <p className="text-gray-700">{article.summary}</p>
            <p>Score: {article.relevance_score ?? "N/A"}</p>
            <button
              onClick={() => onSaveArticle(article)}
              className="mt-2 bg-blue-600 text-white px-3 py-1 rounded hover:bg-blue-700"
            >
              Save to My Articles
            </button>
          </div>
        ))}
      </div>
      <div className="flex justify-between mt-4">
        <button disabled={page === 1} onClick={() => setPage(page - 1)} className="px-3 py-1 bg-gray-300 rounded">
          Prev
        </button>
        <span>Page {page}</span>
        <button disabled={results.length < pageSize} onClick={() => setPage(page + 1)} className="px-3 py-1 bg-gray-300 rounded">
          Next
        </button>
      </div>
    </div>
  );
}
